const [activeTab, setActiveTab] = useState('jadwal');
const [subTab, setSubTab] = useState('s1');

<div className="top-actions">
  <button className="btn-main primary">Daftar Praktikum</button>
  <button className="btn-main outline">Pengulangan</button>
</div>

{/* TAB */}
<div className="tab-menu">
  {['sop','jadwal','silabus','materi'].map(tab => (
    <button
      key={tab}
      className={`tab-btn ${activeTab === tab ? 'active' : ''}`}
      onClick={() => setActiveTab(tab)}
    >
      {tab.toUpperCase()}
    </button>
  ))}
</div>

{/* SUB TAB (ONLY JADWAL) */}
{activeTab === 'jadwal' && (
  <div className="sub-tab">
    {['s1','d3'].map(sub => (
      <button
        key={sub}
        className={subTab === sub ? 'active' : ''}
        onClick={() => setSubTab(sub)}
      >
        {sub.toUpperCase()}
      </button>
    ))}
  </div>
)}

{/* CONTENT */}
<div className="content-card">
  {activeTab === 'sop' && <p>SOP content...</p>}
  {activeTab === 'jadwal' && <p>Jadwal {subTab}</p>}
  {activeTab === 'silabus' && <p>Silabus...</p>}
  {activeTab === 'materi' && <p>Download materi...</p>}
</div>
